parameters.jsCode:
const source = $('Preparer lot emails').first().json;
function extractResponseText(response) {
  if (response.output_text) return response.output_text;
  const output = response.output || [];
  const chunks = [];
  for (const item of output) {
    for (const content of item.content || []) {
      if (content.type === 'output_text' && content.text) chunks.push(content.text);
      if (content.type === 'text' && content.text) chunks.push(content.text);
    }
  }
  return chunks.join('\n') || '{}';
}
const content = extractResponseText(items[0].json);
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { emails: [], global_summary: 'Erreur de parsing de la reponse IA.' };
}
const originalsById = new Map((source.emails || []).map(e => [e.id, e]));
const analyses = (parsed.emails || []).map(a => {
  const original = originalsById.get(a.id) || {};
  const categories = new Set(original.categories || []);
  const urgency = String(a.urgence || 'faible').toLowerCase();
  const action = String(a.action || 'aucune').toLowerCase();
  if (urgency === 'haute') categories.add('IA - Urgent');
  if (action === 'repondre') categories.add('IA - A repondre');
  if (action === 'relancer') categories.add('IA - Relance');
  if (action === 'lire') categories.add('IA - A lire');
  if (action === 'classer') categories.add('IA - A classer');
  if (a.echeance_detectee) categories.add('IA - Echeance');
  categories.add('IA - Traite');
  return {
    ...original,
    analyse: a,
    nextCategories: Array.from(categories)
  };
});
const urgent = analyses.filter(x => x.analyse?.urgence === 'haute');
const repondre = analyses.filter(x => x.analyse?.action === 'repondre');
const echeances = analyses.filter(x => x.analyse?.echeance_detectee);
const drafts = analyses.filter(x => x.analyse?.brouillon_recommande && x.analyse?.brouillon);
function line(x) {
  const a = x.analyse || {};
  return `- ${x.senderName || x.sender} | ${x.subject || '(sans objet)'} | ${a.resume || ''}${a.raison_urgence ? ' | ' + a.raison_urgence : ''}`;
}
const summaryText = [
  `Synthese emails IA - ${new Date().toLocaleString('fr-FR')}`,
  '',
  `Emails traites: ${analyses.length}`,
  `Emails ignores: ${(source.skipped || []).length}`,
  '',
  '1. Urgents',
  urgent.length ? urgent.map(line).join('\n') : '- Aucun email urgent detecte.',
  '',
  '2. Reponses a preparer',
  repondre.length ? repondre.map(line).join('\n') : '- Aucune reponse prioritaire detectee.',
  '',
  '3. Echeances detectees',
  echeances.length ? echeances.map(x => `- ${x.analyse.date_echeance || 'date a confirmer'} | ${x.senderName || x.sender} | ${x.subject || '(sans objet)'} | ${x.analyse.resume || ''}`).join('\n') : '- Aucune echeance detectee.',
  '',
  '4. Brouillons proposes',
  drafts.length ? drafts.map(x => `- ${x.senderName || x.sender} | ${x.subject || '(sans objet)'}`).join('\n') : '- Aucun brouillon propose.',
  '',
  '5. Synthese generale',
  parsed.global_summary || '- Aucun element complementaire.',
  '',
  'Note: les pieces jointes ne sont pas analysees dans cette version.'
].join('\n');
return [{ json: { analyses, summaryText, processedCount: analyses.length, skippedCount: (source.skipped || []).length } }];

const analyses = items[0].json.analyses || [];
return analyses.map(x => ({
  json: {
    id: x.id,
    patchUrl: `https://graph.microsoft.com/v1.0/me/messages/${x.id}`,
    categories: x.nextCategories,
    subject: x.subject,
    sender: x.sender,
    analyse: x.analyse
  }
}));

